        <script>
          document.addEventListener("DOMContentLoaded", () => {
            const blocks = document.querySelectorAll('.product-text-block');
            const imgs = document.querySelectorAll('[id^="product-img-"]');

            if(blocks.length > 0 && window.innerWidth >= 1024) {
              const observer = new IntersectionObserver((entries) => {
                entries.forEach(entry => {
                  if(entry.isIntersecting) {
                    const index = entry.target.getAttribute('data-index');
                    imgs.forEach(img => {
                      img.classList.remove('opacity-100');
                      img.classList.add('opacity-0');
                    });
                    const activeImg = document.getElementById(`product-img-${index}`);
                    if(activeImg) {
                      activeImg.classList.remove('opacity-0');
                      activeImg.classList.add('opacity-100');
                    }
                  }
                });
              }, { rootMargin: '-10% 0px -50% 0px' });

              blocks.forEach(block => observer.observe(block));
            }
          });
        </script>
